<template>
  <div
    :dir="locale === 'ar' ? 'rtl' : 'ltr'"
    class="py-10 bg-grey-lighten-4"
    style="min-height: 100vh"
  >
    <v-container>
      <div class="d-flex align-center justify-space-between mb-6">
        <h2 class="text-h4 font-weight-black text-primary text-capitalize">
          {{ $t("products.search_results", { query: searchQuery }) }}
        </h2>
      </div>

      <v-sheet
        color="primary"
        elevation="2"
        rounded="lg"
        class="header-container px-4 py-3 mb-6"
      >
        <div class="d-flex flex-wrap align-center justify-end w-100 gap-3">
          <v-menu location="bottom end">
            <template v-slot:activator="{ props }">
              <v-btn
                v-bind="props"
                variant="text"
                :color="selectedPrice ? '#ffca28' : 'white'"
                class="text-body-2 font-weight-medium"
                append-icon="mdi-chevron-down"
              >
                {{
                  selectedPrice
                    ? selectedPrice.title
                    : $t("products.sort_by_price")
                }}
              </v-btn>
            </template>
            <v-list density="compact" rounded="lg">
              <v-list-item
                v-if="selectedPrice"
                @click="selectedPrice = null"
                :title="$t('products.cancel_sort')"
                color="error"
                class="text-error"
              >
                <template v-slot:prepend>
                  <v-icon icon="mdi-close" color="error"></v-icon>
                </template>
              </v-list-item>
              <v-list-item
                v-for="item in priceOptions"
                :key="item.value"
                :title="item.title"
                :value="item.value"
                @click="selectedPrice = item"
                :active="selectedPrice?.value === item.value"
                color="primary"
              ></v-list-item>
            </v-list>
          </v-menu>
        </div>
      </v-sheet>

      <div class="Product-section">
        <v-row v-if="loading" justify="center" class="py-15">
          <v-progress-circular
            indeterminate
            color="primary"
            size="64"
          ></v-progress-circular>
        </v-row>

        <v-row
          v-else-if="paginatedProducts.length === 0"
          justify="center"
          class="py-15"
        >
          <v-col cols="12" class="text-center">
            <v-icon size="80" color="grey-lighten-2" class="mb-4"
              >mdi-package-variant-closed</v-icon
            >
            <h3 class="text-h4 font-weight-bold text-grey-darken-1">
              {{ $t("products.no_results_found") }}
            </h3>
            <p class="mt-3 text-grey">
              {{ $t("products.try_different_keywords") }}
            </p>
          </v-col>
        </v-row>

        <v-row v-else>
          <v-col
            cols="12"
            sm="6"
            md="6"
            lg="4"
            v-for="product in paginatedProducts"
            :key="product.id"
          >
            <ProductCard :product="product" />
          </v-col>
        </v-row>

        <v-row justify="center" class="mt-8 mb-4" v-if="totalPages > 1">
          <v-col cols="auto">
            <v-pagination
              v-model="currentPage"
              :length="totalPages"
              :total-visible="7"
              active-color="primary"
              color="grey-lighten-2"
              rounded="circle"
              elevation="1"
            ></v-pagination>
          </v-col>
        </v-row>
      </div>
    </v-container>

    <PopUp />
  </div>
</template>

<script setup>
import { onMounted, watch, ref, computed } from "vue";
import { useI18n } from "vue-i18n";
const { locale, t } = useI18n();
import { useRoute } from "vue-router";
import api from "@/axios";
import PopUp from "@/components/PopUp.vue";
import ProductCard from "@/components/ProductCard.vue";

const route = useRoute();

const searchProducts = ref([]);
const loading = ref(false);
const searchQuery = ref("");

const loadSearchProducts = async (q) => {
  if (!q) return;
  loading.value = true;
  searchQuery.value = q;
  try {
    const res = await api.get(`/products?search=${q}`);
    searchProducts.value = res.data?.data || res.data || [];
  } catch (error) {
    console.error(error);
  } finally {
    loading.value = false;
  }
};

watch(
  () => route.query.q,
  async (newQ) => {
    currentPage.value = 1;
    await loadSearchProducts(newQ);
  }
);

onMounted(async () => {
  await loadSearchProducts(route.query.q);
});

// --- Filter Logic States ---
const selectedPrice = ref(null);
const priceOptions = computed(() => [
  { title: t("products.price_low_high"), value: "asc" },
  { title: t("products.price_high_low"), value: "desc" },
]);

// --- Pagination Logic ---
const currentPage = ref(1);
const itemsPerPage = 8;

const filteredProducts = computed(() => {
  let products = searchProducts.value ? [...searchProducts.value] : [];

  if (selectedPrice.value) {
    const isAsc = selectedPrice.value.value === "asc";
    products.sort((a, b) => {
      const priceA = a.price * (1 - a.discountPercentage / 100);
      const priceB = b.price * (1 - b.discountPercentage / 100);
      return isAsc ? priceA - priceB : priceB - priceA;
    });
  }

  return products;
});

watch([selectedPrice], () => {
  currentPage.value = 1;
});

const totalPages = computed(() => {
  return Math.ceil(filteredProducts.value.length / itemsPerPage);
});

const paginatedProducts = computed(() => {
  const start = (currentPage.value - 1) * itemsPerPage;
  const end = start + itemsPerPage;
  return filteredProducts.value.slice(start, end);
});
</script>

<style scoped>
/* ================= ألوان المتغيرات ================= */
.text-primary-dark {
  color: rgb(14, 22, 103) !important;
}
</style>
